+/// Adapt a TimelineEvent from storage into a render-ready TimelineRow.
+#[must_use]
+pub fn adapt_timeline_event(event: &TimelineEvent) -> TimelineRow {
+    let severity_style = severity_to_style(&event.severity);
+    let agent_label = event
+        .pane_info
+        .agent_type
+        .as_deref()
+        .unwrap_or("unknown")
